        top = code.split('/')[0][:3]
        if top in level4_symbols:
            counts[top][year] += 1

# For each group, compute EMA across years (alpha=0.1)
alpha = 0.1
results = []
for sym, year_counts in counts.items():
    years = sorted(year_counts.keys())
    if not years:
        continue
    ema_by_year = {}
    ema = None
    for y in years:
        c = year_counts[y]
        if ema is None:
            ema = c
        else:
            ema = alpha * c + (1 - alpha) * ema
        ema_by_year[y] = ema
    # find year with max EMA
